def can_partition(nums, k):
    total = sum(nums)
    if k == 0:
        return False
    if total % k != 0:
        return False
    target = total // k
    current_sum = 0
    partitions = 0
    for num in nums:
        current_sum += num
        if current_sum == target:
            partitions += 1
            current_sum = 0
        elif current_sum > target:
            return False
    return partitions == k

